                    assert(new_uf.parent[i as int] == root_i);
                    assert(new_uf.parent[root_i as int] == root_i);
                }
            } else {
                let p = uf.parent[j as int];
                if p != j {
                    Self::lemma_spec_find_stable_recursive(uf, i, new_uf, p as usize);
                }
            }
        }
        // </proofs>

        // Following is the block for the main specification
        // <spec>
        pub fn find(&mut self, i: usize) -> (root: usize)
            requires
                old(self).is_valid(),
                i < old(self).parent.len(),
            ensures
                self.is_valid(),
                root == self.spec_find(i),
                forall|j: usize| 0 <= j < self.parent.len() ==> 
                    #[trigger] self.spec_find(j) == old(self).spec_find(j),
                self.parent.len() == old(self).parent.len(),
                self.rank == old(self).rank,
